"use client";

import { BRAND_ICON_SRC } from "@/lib/brand";
import { cn } from "@/lib/utils";

interface BrandLoadingProps {
  label?: string;
  fullScreen?: boolean;
  className?: string;
}

export function BrandLoading({
  label = "Loading...",
  fullScreen = false,
  className,
}: BrandLoadingProps) {
  return (
    <div
      className={cn(
        "flex flex-col items-center justify-center gap-4",
        fullScreen && "min-h-svh",
        className,
      )}
      role="status"
      aria-live="polite"
      aria-busy="true"
    >
      {/* eslint-disable-next-line @next/next/no-img-element */}
      <img
        src={BRAND_ICON_SRC}
        alt=""
        width={56}
        height={56}
        className="dc-brand-float size-14 object-contain"
        draggable={false}
      />
      <div className="h-1 w-28 overflow-hidden rounded-full bg-primary/15">
        <div className="dc-brand-shimmer h-full w-1/2 rounded-full bg-primary" />
      </div>
      {label ? (
        <p className="text-muted-foreground animate-pulse text-sm">{label}</p>
      ) : null}
    </div>
  );
}
